/**
 * useEdgeTTS — Microsoft Edge Neural TTS via the API server.
 *
 * Produces natural Indian-accented speech for 13 languages with real
 * male / female neural voices. Same interface as useSpeechSynthesis so
 * pages can swap with minimal changes.
 *
 * GLOBAL SINGLETON: All hook instances share a single Audio element so
 * English Guru and Interview Ace (or any two tools) can never speak
 * simultaneously — calling speak() anywhere immediately stops whatever
 * else is playing.
 */
import { useState, useEffect, useRef, useCallback } from "react";

export type VoiceGender = "male" | "female" | "auto";

export type EdgeSpeakOptions = {
  voiceGender?: VoiceGender;
  /** playbackRate multiplier — default 1.0 (Edge voices are already natural speed) */
  rate?: number;
  /** ignored for Edge TTS (pitch is set by the neural model, not adjustable) */
  pitch?: number;
  /**
   * Tutor voice style key (e.g. "priya", "arjun", "rahul"). When supplied, the
   * API server maps this to a specific Edge Neural voice so each tutor has a
   * distinct accent. Falls back to gender-based selection when absent.
   */
  voiceStyle?: string;
  /**
   * Native/helper language name (e.g. "Malayalam"). When supplied, the API
   * server splits a mixed reply into native-script and English runs and voices
   * each run with its own neural voice — so an English word inside a native
   * explanation is spoken naturally instead of by the native voice (and vice
   * versa). Omit for single-voice output (greetings, English-only replies).
   */
  nativeLanguage?: string;
};

const BASE = (import.meta.env.BASE_URL ?? "/").replace(/\/$/, "");

// ---------------------------------------------------------------------------
// Audio context unlock
//
// Chrome's autoplay policy blocks audio.play() unless called from within a
// user-gesture event stack. Because TTS fetches take 1-4 seconds (AI + Edge
// network), the gesture context has expired long before play() is attempted.
//
// Strategy — two-layer unlock:
//
// Layer 1 (AudioContext): Resume an AudioContext in the click handler.
//   Chrome's sticky-activation fires the moment any user gesture occurs;
//   a running AudioContext propagates that permission to HTMLAudioElement
//   plays on the same origin.
//
// Layer 2 (pre-blessed element): Also create an HTMLAudioElement inside the
//   gesture and call play() on it immediately. Chrome "blesses" the element
//   itself, and that blessing survives src changes — so speak() can reuse
//   the same element with a new URL and play() always succeeds.
//
// Both layers run together; either alone can fail on certain browser/site
// combinations (e.g. deployed origins with lower media-engagement scores).
// ---------------------------------------------------------------------------
let _unlocked = false;
let _unlockedEl: HTMLAudioElement | null = null; // pre-blessed element for speak()
let _audioCtx: AudioContext | null = null;       // running AudioContext

// Tiny valid silent MP3 — played inside the user gesture to trigger blessing.
const SILENT_MP3 =
  "data:audio/mpeg;base64,";

/**
 * unlockAudio — call synchronously from inside a click / keydown handler.
 *
 * Two-layer unlock to maximise cross-browser reliability:
 *  • Layer 1 — resume an AudioContext so Chrome's sticky-activation propagates
 *    to all HTMLAudioElement plays on this origin.
 *  • Layer 2 — create and play a silent HTMLAudioElement; Chrome "blesses" the
 *    specific element, and that blessing survives src changes.  The element is
 *    stored in _unlockedEl so speak() can reuse it without a fresh play() call.
 *
 * Safe to call multiple times — once unlocked it is a no-op.
 */
export function unlockAudio(): void {
  if (_unlocked) return;
  _unlocked = true;

  // Layer 1 — AudioContext sticky activation
  // Reuse an existing context rather than creating a new one on each call so
  // repeated blocked attempts don't accumulate suspended AudioContext objects.
  try {
    const AC = window.AudioContext ?? (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
    if (AC) {
      if (!_audioCtx || _audioCtx.state === "closed") {
        _audioCtx = new AC();
      }
      _audioCtx.resume().catch(() => {});
    }
  } catch { /* AudioContext not supported — safe to ignore */ }

  // Layer 2 — pre-bless an HTMLAudioElement
  // Only reset _unlocked to false if play() is actually blocked (NotAllowedError),
  // so the AudioContext layer is not discarded along with the element layer.
  try {
    const a = new Audio(SILENT_MP3);
    a.volume = 0;
    a.play()
      .then(() => {
        a.pause();
        a.volume = 1;
        a.src = ""; // clear silent data; src will be overwritten in speak()
        _unlockedEl = a; // store the blessed element for speak() to reuse
      })
      .catch(() => {
        // Element play was blocked — allow a retry on the next gesture.
        // Do NOT reset _unlocked here: the AudioContext layer may have already
        // established sticky activation, so retrying both layers next time is fine.
        _unlocked = false;
      });
  } catch {
    _unlocked = false;
  }
}

// ---------------------------------------------------------------------------
// Module-level singleton — exactly one audio element and one AbortController
// across the entire app lifetime. Guarantees only one AI voice at a time.
// ---------------------------------------------------------------------------
let _audio: HTMLAudioElement | null = null;
let _abort: AbortController | null = null;
let _url:   string | null = null;
// Hook instances register here to be notified when global stop happens
// so they can reset their own isSpeaking state.
const _stopListeners = new Set<() => void>();

// ---------------------------------------------------------------------------
// Live "mouth level" singleton — real audio-driven lip-sync data.
//
// Rather than hook a live AnalyserNode onto the playing <audio> element (which
// would risk interfering with the delicate autoplay-unlock dance above), we
// decode each chunk's MP3 blob OFFLINE the moment it arrives — a separate,
// read-only pass over the same bytes — and precompute a small envelope:
//   • openness — RMS loudness per ~20ms window, normalised to that clip's own
//     peak, i.e. "how wide should the mouth be right now"
//   • width    — a zero-crossing-rate proxy for spectral brightness, i.e.
//     "rounder ('ah/oh') vs. wider ('ee/ss') mouth shape right now"
// During playback a rAF loop reads audio.currentTime and looks up (with
// linear interpolation) into that precomputed envelope — so the avatar's
// mouth is driven by the ACTUAL waveform of what's playing, not a timer or
// a coin-flip, while never touching the playback graph itself.
// ---------------------------------------------------------------------------
export type MouthLevel = { openness: number; width: number };
const CLOSED_MOUTH: MouthLevel = { openness: 0, width: 0 };
let _mouthLevel: MouthLevel = CLOSED_MOUTH;
const _mouthListeners = new Set<(m: MouthLevel) => void>();

function publishMouthLevel(m: MouthLevel): void {
  // Skip near-identical updates (e.g. repeated silence) to avoid pointless re-renders.
  if (
    Math.abs(m.openness - _mouthLevel.openness) < 0.012 &&
    Math.abs(m.width - _mouthLevel.width) < 0.012
  ) {
    return;
  }
  _mouthLevel = m;
  _mouthListeners.forEach((fn) => fn(m));
}

/** Subscribe to live mouth-level updates. Returns an unsubscribe function. */
export function subscribeMouthLevel(cb: (m: MouthLevel) => void): () => void {
  _mouthListeners.add(cb);
  cb(_mouthLevel);
  return () => { _mouthListeners.delete(cb); };
}

/**
 * useMouthLevel — React hook wrapper around the singleton above.
 * Pass the avatar's own `isSpeaking` prop as `active`: while false, the
 * avatar simply reports a closed mouth and never subscribes, so idle
 * avatars don't re-render on someone else's speech.
 */
export function useMouthLevel(active: boolean): MouthLevel {
  const [level, setLevel] = useState<MouthLevel>(CLOSED_MOUTH);
  useEffect(() => {
    if (!active) { setLevel(CLOSED_MOUTH); return; }
    return subscribeMouthLevel(setLevel);
  }, [active]);
  return level;
}

// Monotonic generation token — bumped on every speak() and on globalStop().
// Any in-flight chunk-chain recursion compares its captured token against the
// live counter at each checkpoint and quietly stops if it no longer matches,
// so a superseded utterance can never resume playback or fire a stray onEnd.
let _speakGen = 0;

// Reused across chunks/utterances rather than spun up per-clip — browsers cap
// concurrent AudioContexts, and decoding doesn't need the "unlocked" one above.
let _decodeCtx: AudioContext | null = null;
function getDecodeCtx(): AudioContext | null {
  try {
    if (!_decodeCtx || _decodeCtx.state === "closed") {
      const AC = window.AudioContext ?? (window as unknown as { webkitAudioContext?: typeof AudioContext }).webkitAudioContext;
      if (!AC) return null;
      _decodeCtx = new AC();
    }
    return _decodeCtx;
  } catch {
    return null;
  }
}

const ENVELOPE_HOP_SEC = 0.02; // ~50 samples/sec — smooth enough for a mouth, cheap to compute/store

type Envelope = { hop: number; openness: Float32Array; width: Float32Array };

/** Decode a TTS blob offline and derive a loudness+brightness envelope for lip-sync. Never throws — returns null on any failure so playback is unaffected. */
async function computeEnvelope(blob: Blob): Promise<Envelope | null> {
  const ctx = getDecodeCtx();
  if (!ctx) return null;
  try {
    const arrBuf = await blob.arrayBuffer();
    const audioBuf = await ctx.decodeAudioData(arrBuf);
    const data = audioBuf.getChannelData(0);
    const sr = audioBuf.sampleRate;
    const hopSamples = Math.max(1, Math.round(sr * ENVELOPE_HOP_SEC));
    const frames = Math.max(1, Math.ceil(data.length / hopSamples));
    const openness = new Float32Array(frames);
    const width = new Float32Array(frames);
    let peak = 0.0001;
    for (let f = 0; f < frames; f++) {
      const start = f * hopSamples;
      const end = Math.min(start + hopSamples, data.length);
      let sumSq = 0;
      let zc = 0;
      let prev = data[start] ?? 0;
      for (let i = start; i < end; i++) {
        const s = data[i] ?? 0;
        sumSq += s * s;
        if (i > start && (s >= 0) !== (prev >= 0)) zc++;
        prev = s;
      }
      const n = Math.max(1, end - start);
      const rms = Math.sqrt(sumSq / n);
      if (rms > peak) peak = rms;
      openness[f] = rms;
      width[f] = Math.min(1, zc / (n * 0.35));
    }
    for (let f = 0; f < frames; f++) openness[f] = Math.min(1, (openness[f] ?? 0) / peak);
    return { hop: ENVELOPE_HOP_SEC, openness, width };
  } catch {
    return null;
  }
}

/**
 * splitIntoSpeechChunks — break a reply into sentence-sized pieces so speak()
 * can start playing the FIRST sentence as soon as it's synthesised while the
 * rest keeps synthesising in the background, instead of the whole reply
 * going quiet for however long the full paragraph takes to render.
 * Very short fragments get merged into the next chunk so we never fire a
 * TTS request for a two-word sliver. Falls back to the whole text as a
 * single chunk if the split produces nothing usable.
 */
function splitIntoSpeechChunks(text: string): string[] {
  const clean = text.trim();
  if (!clean) return [];
  const raw = clean.split(/(?<=[.!?])\s+(?=[A-Z0-9"'])/g).map((s) => s.trim()).filter(Boolean);
  if (raw.length <= 1) return [clean];
  const merged: string[] = [];
  for (const part of raw) {
    const last = merged[merged.length - 1];
    if (last !== undefined && last.length < 40) {
      merged[merged.length - 1] = `${last} ${part}`;
    } else {
      merged.push(part);
    }
  }
  return merged.length > 0 ? merged : [clean];
}

// Small natural gap between chunks — real speech has a breath/beat at full
// stops; stitching chunks with zero gap sounds clipped, and too large a gap
// sounds like separate thoughts rather than one flowing reply.
const CHUNK_GAP_MS = 140;


function globalStop() {
  _speakGen++; // supersede any in-flight chunk chain — it will see the mismatch and quietly stop
  _abort?.abort();
  _abort = null;
  if (_audio) {
    _audio.pause();
    _audio.onended = null;
    _audio.onerror = null;
    _audio.src    = "";
    _audio        = null;
  }
  if (_url) { URL.revokeObjectURL(_url); _url = null; }
  publishMouthLevel(CLOSED_MOUTH);
  // Notify all mounted hook instances so isSpeaking resets everywhere
  _stopListeners.forEach(fn => fn());
}

// ---------------------------------------------------------------------------

/**
 * playChunkChain — recursively fetches, plays, and (for the mouth envelope)
 * decodes one chunk at a time, prefetching the NEXT chunk's audio while the
 * current one plays so there's no dead air between sentences. Every step
 * re-checks `myGen` against the live `_speakGen` counter and quietly stops
 * the instant they diverge — i.e. a newer speak() or an explicit stop()
 * superseded this utterance. A chunk that fails to fetch/synthesise is
 * skipped (not fatal) so one bad sentence doesn't silence the whole reply.
 */
function playChunkChain(
  chunks: string[],
  index: number,
  myGen: number,
  language: string,
  gender: "male" | "female",
  options: EdgeSpeakOptions,
  onAllDone: () => void,
): void {
  if (myGen !== _speakGen) return; // superseded before this chunk even started
  if (index >= chunks.length) { onAllDone(); return; }

  const chunkText = chunks[index]!;
  const ctrl = new AbortController();
  _abort = ctrl;
  // Per-chunk hang guard — chunks are short, so 12s is already generous.
  const hangTimer = setTimeout(() => { if (_abort === ctrl) ctrl.abort(); }, 12_000);
  const next = () => playChunkChain(chunks, index + 1, myGen, language, gender, options, onAllDone);

  fetch(`${BASE}/api/tts`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    credentials: "include",
    body: JSON.stringify({
      text: chunkText, language, gender,
      voiceStyle: options.voiceStyle, nativeLanguage: options.nativeLanguage,
    }),
    signal: ctrl.signal,
  })
    .then(async (res) => {
      clearTimeout(hangTimer);
      if (myGen !== _speakGen) return;
      if (!res.ok || ctrl.signal.aborted) { next(); return; }

      const blob = await res.blob();
      if (myGen !== _speakGen) return;
      if (blob.size < 512) {
        console.warn("[TTS] audio blob too small (%d bytes) — skipping chunk", blob.size);
        next();
        return;
      }

      const url = URL.createObjectURL(blob);
      _url = url;

      // Prefer the pre-blessed element from unlockAudio() for the very first
      // chunk of the very first utterance; every later chunk gets a fresh one.
      let audio: HTMLAudioElement;
      if (_unlockedEl) {
        audio = _unlockedEl;
        _unlockedEl = null;
      } else {
        audio = new Audio();
      }
      audio.src = url;
      _audio = audio;

      const rate = options.rate;
      if (rate && rate !== 1.0) audio.playbackRate = Math.max(0.8, Math.min(rate, 2.0));

      // Decode for lip-sync IN PARALLEL with playback starting below — this
      // never blocks or touches the playback graph, so it can't affect the
      // autoplay unlock. If it fails for any reason, envelope stays null and
      // the mouth simply doesn't animate for this chunk (playback is fine).
      let envelope: Envelope | null = null;
      void computeEnvelope(blob).then((env) => { envelope = env; });

      const tick = () => {
        // Stop the instant this chunk is no longer the live one — natural
        // end, error, or a newer speak()/stop() — and leave the mouth closed.
        if (myGen !== _speakGen || _audio !== audio) { publishMouthLevel(CLOSED_MOUTH); return; }
        if (!audio.paused && envelope) {
          const idx = audio.currentTime / envelope.hop;
          const i0 = Math.max(0, Math.floor(idx));
          const i1 = Math.min(i0 + 1, envelope.openness.length - 1);
          const frac = idx - i0;
          const o0 = envelope.openness[Math.min(i0, envelope.openness.length - 1)] ?? 0;
          const o1 = envelope.openness[i1] ?? o0;
          const w0 = envelope.width[Math.min(i0, envelope.width.length - 1)] ?? 0;
          const w1 = envelope.width[i1] ?? w0;
          publishMouthLevel({ openness: o0 + (o1 - o0) * frac, width: w0 + (w1 - w0) * frac });
        }
        requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);

      const advance = () => {
        URL.revokeObjectURL(url);
        if (_url === url) _url = null;
        if (_audio === audio) _audio = null;
        publishMouthLevel(CLOSED_MOUTH);
        if (myGen !== _speakGen) return; // superseded — do not continue the chain
        if (index + 1 < chunks.length) {
          setTimeout(next, CHUNK_GAP_MS);
        } else {
          onAllDone();
        }
      };
      audio.onended = advance;
      audio.onerror = advance;

      try {
        await audio.play();
      } catch (playErr) {
        // NotAllowedError = autoplay policy still blocking despite unlock.
        console.warn("[TTS] audio.play() blocked:", playErr);
        advance();
      }
    })
    .catch(() => {
      clearTimeout(hangTimer);
      if (myGen !== _speakGen) return;
      next(); // this chunk failed outright — try the next one rather than going silent
    });
}

export function useEdgeTTS() {
  const [isSpeaking, setIsSpeaking] = useState(false);
  // Track whether THIS instance is the active speaker so only it fires onEnd
  const ownerRef = useRef(false);

  // Register / deregister global-stop listener on mount / unmount
  useEffect(() => {
    const onGlobalStop = () => {
      if (ownerRef.current) {
        ownerRef.current = false;
        setIsSpeaking(false);
      }
    };
    _stopListeners.add(onGlobalStop);
    return () => {
      _stopListeners.delete(onGlobalStop);
      // If this instance was speaking when unmounted, relinquish ownership FIRST
      // so no post-unmount setIsSpeaking fires, then stop global audio.
      if (ownerRef.current) {
        ownerRef.current = false;
        globalStop();
      }
    };
  }, []);

  const stop = useCallback(() => {
    globalStop();
  }, []);

  const speak = useCallback(
    async (
      text: string,
      language = "English",
      onEnd?: () => void,
      options: EdgeSpeakOptions = {},
    ) => {
      if (!text.trim()) { onEnd?.(); return; }

      // Stop any currently-playing audio globally (resets all hook isSpeaking
      // states and supersedes any in-flight chunk chain via _speakGen).
      globalStop();
      const myGen = _speakGen;

      ownerRef.current = true;
      setIsSpeaking(true);

      const gender: "male" | "female" =
        options.voiceGender === "male" ? "male" : "female";

      // Sentence-chunked so the FIRST sentence can start playing as soon as
      // it's synthesised, while later sentences synthesise in the background —
      // this is what makes a long reply start talking in ~1s instead of
      // going quiet for the whole paragraph's synthesis time.
      const chunks = splitIntoSpeechChunks(text);
      if (chunks.length === 0) {
        if (ownerRef.current) { ownerRef.current = false; setIsSpeaking(false); }
        onEnd?.();
        return;
      }

      playChunkChain(chunks, 0, myGen, language, gender, options, () => {
        // Only the owner fires onEnd — prevents double-fire if globally stopped
        if (ownerRef.current) {
          ownerRef.current = false;
          setIsSpeaking(false);
          onEnd?.();
        }
      });
    },
    [],
  );

  return {
    isSpeaking,
    isSupported: true as const,
    speak,
    stop,
  };
}
